class I18nManager{constructor(){this.currentLang=this.getStoredLanguage()||this.getBrowserLanguage();this.translations={};this.isLoaded=false;this.init();}async init(){try{await this.loadTranslations(this.currentLang);this.setupLanguageSwitcher();this.applyTranslations();this.isLoaded=true;document.documentElement.setAttribute('data-lang',this.currentLang);document.dispatchEvent(new CustomEvent('i18n:loaded',{detail:{language:this.currentLang}}));}catch(error){console.error('Failed to initialize i18n:',error);}}getStoredLanguage(){return localStorage.getItem('preferred-language');}getBrowserLanguage(){const browserLang=navigator.language||navigator.userLanguage;return browserLang.startsWith('ru')? 'ru':'en';}async loadTranslations(lang){if(this.translations[lang]){return this.translations[lang];}try{const response=await fetch(`/assets/i18n/${lang}.json`);if(!response.ok){throw new Error(`Failed to load translations for ${lang}`);}this.translations[lang]=await response.json();return this.translations[lang];}catch(error){console.error(`Error loading translations for ${lang}:`,error);if(lang!=='en'){return await this.loadTranslations('en');}throw error;}}async switchLanguage(lang){if(lang===this.currentLang)return;try{this.showLoadingState();await this.loadTranslations(lang);this.currentLang=lang;localStorage.setItem('preferred-language',lang);this.applyTranslations();document.documentElement.setAttribute('data-lang',lang);document.documentElement.setAttribute('lang',lang);this.updateLanguageSwitcher();this.hideLoadingState();document.dispatchEvent(new CustomEvent('i18n:languageChanged',{detail:{language:lang,previousLanguage:this.currentLang}}));}catch(error){console.error('Failed to switch language:',error);this.hideLoadingState();}}applyTranslations(){const translations=this.translations[this.currentLang];if(!translations)return;const elements=document.querySelectorAll('[data-i18n]');elements.forEach(element=>{const key=element.getAttribute('data-i18n');const translation=this.getNestedValue(translations,key);if(translation){if(element.tagName==='INPUT'||element.tagName==='TEXTAREA'){element.placeholder=translation;}else if(element.tagName==='IMG'){element.alt=translation;}else{element.textContent=translation;}}});if(translations.site?.title){document.title=translations.site.title;}this.updateAccessibilityAttributes(translations);}getNestedValue(obj,key){return key.split('.').reduce((current,keyPart)=>{return current&&current[keyPart]!==undefined ? current[keyPart]:null;},obj);}setupLanguageSwitcher(){let switcher=document.querySelector('.language-switcher');if(!switcher){switcher=this.createLanguageSwitcher();const header=document.querySelector('.site-header');if(header){header.appendChild(switcher);}}this.updateLanguageSwitcher();}createLanguageSwitcher(){const switcher=document.createElement('div');switcher.className='language-switcher';switcher.setAttribute('role','group');switcher.setAttribute('aria-label','Language selection');switcher.innerHTML=`<button type="button" class="lang-btn active" data-lang="en" aria-pressed="true" aria-label="Switch to English">EN</button><button type="button" class="lang-btn" data-lang="ru" aria-pressed="false" aria-label="Переключить на русский">RU</button>`;switcher.querySelectorAll('.lang-btn').forEach(btn=>{btn.addEventListener('click',()=>{const lang=btn.getAttribute('data-lang');this.switchLanguage(lang);});});return switcher;}updateLanguageSwitcher(){const switcher=document.querySelector('.language-switcher');if(!switcher)return;switcher.querySelectorAll('.lang-btn').forEach(btn=>{const lang=btn.getAttribute('data-lang');const isActive=lang===this.currentLang;btn.classList.toggle('active',isActive);btn.setAttribute('aria-pressed',isActive.toString());});}updateAccessibilityAttributes(translations){const skipLink=document.querySelector('.skip-link');if(skipLink&&translations.accessibility?.skip_to_content){skipLink.textContent=translations.accessibility.skip_to_content;}const menuButton=document.querySelector('.menu-icon');if(menuButton){const label=menuButton.classList.contains('active')? translations.accessibility?.close_menu:translations.accessibility?.open_menu;if(label)menuButton.setAttribute('aria-label',label);}}showLoadingState(){const body=document.body;body.classList.add('i18n-loading');if(!document.querySelector('.i18n-loading-overlay')){const overlay=document.createElement('div');overlay.className='i18n-loading-overlay';overlay.innerHTML=`<div class="loading-spinner"><div class="spinner"></div><span>Loading...</span></div>`;body.appendChild(overlay);}}hideLoadingState(){const body=document.body;body.classList.remove('i18n-loading');const overlay=document.querySelector('.i18n-loading-overlay');if(overlay){overlay.remove();}}t(key,params={}){const translation=this.getNestedValue(this.translations[this.currentLang],key);if(!translation)return key;return Object.keys(params).reduce((text,param)=>{return text.replace(new RegExp(`{{\\s*${param}\\s*}}`,'g'),params[param]);},translation);}getCurrentLanguage(){return this.currentLang;}getAvailableLanguages(){return['en','ru'];}isReady(){return this.isLoaded;}}window.i18n=new I18nManager();window.t=(key,params)=>window.i18n.t(key,params);if(typeof module!=='undefined'&&module.exports){module.exports=I18nManager;}